func TestHydrator_WithMockGraphClient(t *testing.T) {
	mockGraph := &MockGraphClient{
		QueryFunc: func(ctx context.Context, query string) (string, error) {
			return "Mock context from graph", nil
		},
	}

	config := teamsmemory.HydrationConfig{
		PostCompaction: teamsmemory.PostCompactionConfig{
			Enabled:           true,
			MaxRecoveryTokens: 1500,
		},
	}

	hydrator, err := teamsmemory.NewHydrator(config, mockGraph)
	if err != nil {
		t.Fatalf("NewHydrator() failed: %v", err)
	}

	ctx := context.Background()
	result, err := hydrator.HydratePostCompaction(ctx, "loop-001")
	if err != nil {
		t.Fatalf("HydratePostCompaction() failed: %v", err)
	}

	if result == nil {
		t.Fatal("HydratePostCompaction() returned nil result")
	}

	// Should have context from mock
	if result.Context == "" {
		t.Error("HydratePostCompaction() should return context from mock graph client")
	}
}

